\title{Diffusion-Assisted Latent Wasserstein GAN for Robust Generative Modeling}

\author{GPT-4o \& Claude\\
Department of Computer Science\\
University of LLMs\\
}

\newcommand{\fix}{\marginpar{FIX}}
